import { useEffect, useState } from 'react';
import API from '../services/api';

function Leads() {
  const [leads, setLeads] = useState([]);

  useEffect(() => {
    getLeads();
  }, []);

  const getLeads = async () => {
    const res = await API.get('/leads');
    setLeads(res.data);
  };

  return (
    <div>
      <h2>Lead Management</h2>

      <table>
        <thead>
          <tr>
            <th>Name</th>
            <th>Country</th>
            <th>Status</th>
            <th>Priority</th>
          </tr>
        </thead>

        <tbody>
          {leads.map((lead) => (
            <tr key={lead._id}>
              <td>{lead.fullName}</td>
              <td>{lead.country}</td>
              <td>{lead.leadStatus}</td>
              <td>{lead.priority}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Leads;
